---@class LRTHelper
local LRTHelper = LxClass("LRTHelper", nil)


function LRTHelper.SupportsStencilRT(rt)
	return URenderTexture.SupportsStencil(rt)
end

function LRTHelper.AdjustPowerOfTwo(len)
	if (len <= 128) then return 128 end
	if (len <= 256) then return 256 end
	if (len <= 512) then return 512 end
	if (len <= 1024) then return 1024 end
	return 1024
end

function LRTHelper.GetTemporary(name, width, height, textureFormat, antiAliasing, depthBuffer, filterMode, wrapMode, isIgnoreSquare)
	local texWidth = width
	local texHeight = height
	if not isIgnoreSquare then
		texWidth = LRTHelper.AdjustPowerOfTwo(width)
		texHeight = LRTHelper.AdjustPowerOfTwo(height)
	end

	textureFormat = textureFormat or URenderTextureFormat.ARGB32
	filterMode = filterMode or UFilterMode.Bilinear
	wrapMode = wrapMode or UTextureWrapMode.Clamp
	antiAliasing = antiAliasing or 2
	depthBuffer = depthBuffer or 24

	if (not SystemInfo.SupportsRenderTextureFormat(textureFormat)) then
		LogError("UnSupport RendererTexture Format " .. textureFormat)
		return nil
	end

	local rt = URenderTexture.GetTemporary(texWidth, texHeight, depthBuffer, textureFormat)
	rt.name = name
	rt.filterMode = filterMode
	rt.wrapMode = wrapMode
	--rt.antiAliasing = antiAliasing
	rt.autoGenerateMips = false
	return rt
end

function LRTHelper.ReleaseTemporary(rt)
